create table dirkspzm32.lvs_anlief_id_liste (
    sid              varchar2(2 char) not null enable,
    firma_nr         number(6, 0) not null enable,
    anlief_id        varchar2(20 char) not null enable,
    anlief_id_typ    varchar2(10 char) not null enable,
    scan_string      varchar2(255 char),
    login_id         number(*, 0) not null enable,
    arbeitsplatz_id  number(*, 0) not null enable,
    status           varchar2(10 char) not null enable,
    buch_datum       date not null enable,
    erzeuger_modul   varchar2(5 char) not null enable,
    bearbeiter_modul varchar2(5 char) not null enable
);

alter table dirkspzm32.lvs_anlief_id_liste
    add constraint pk_anlief_id_liste
        primary key ( sid,
                      anlief_id,
                      anlief_id_typ,
                      login_id )
            using index enable;


